mapper.select:
SELECT e.id AS id, e.project_id AS projectId, p.name AS projectName, p.code AS projectCode, e.suite_id AS suiteId, s.name AS suiteName, e.case_id AS caseId, tc.name AS caseName, e.trigger_type AS triggerType, e.status AS status, e.total_count AS totalCases, e.pass_count AS passedCases, e.fail_count AS failedCases, 0 AS skippedCases, e.start_time AS startTime, e.end_time AS endTime, e.create_time AS createTime FROM execution e LEFT JOIN project p ON p.id = e.project_id LEFT JOIN test_suite s ON s.id = e.suite_id LEFT JOIN test_case tc ON tc.id = e.case_id
AND e.project_id = #{projectId}
AND e.status = #{status}
ORDER BY e.create_time DESC
